import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../../shared/models/models.dart';import '../data/demo_search_data.dart';
final searchProvider=StateNotifierProvider<SearchController,SearchQuery>((ref)=>SearchController());
class SearchController extends StateNotifier<SearchQuery>{SearchController():super(SearchQuery(start:DateTime.now().copyWith(hour:18,minute:0),end:DateTime.now().copyWith(hour:22,minute:0),vehicle:demoVehicles.first));void destination(Destination d)=>state=state.copyWith(destination:d);void vehicle(Vehicle v)=>state=state.copyWith(vehicle:v);void duration(int h)=>state=state.copyWith(end:state.start.add(Duration(hours:h)));void toggle(String f){final s={...state.filters};s.contains(f)?s.remove(f):s.add(f);state=state.copyWith(filters:s);}void sort(String s)=>state=state.copyWith(sort:s);void reset()=>state=SearchQuery(start:DateTime.now().copyWith(hour:18,minute:0),end:DateTime.now().copyWith(hour:22,minute:0),vehicle:demoVehicles.first);}
